def range_summary(nums):
    if not nums:
        return ''

    nums.sort()
    ranges = []
    start = nums[0]

    for i in range(1, len(nums)):
        if nums[i] != nums[i-1] + 1:
            if start == nums[i-1]:
                ranges.append(str(start))
            else:
                ranges.append(f'{start}-{nums[i-1]}')
            start = nums[i]

    # Append the last range
    if start == nums[-1]:
        ranges.append(str(start))
    else:
        ranges.append(f'{start}-{nums[-1]}')

    return ','.join(ranges)
